    try {
      setLoading(true);
      setError(null);
      const response = await getQuickBooksStatus(organizationId);
      const status = transformQuickBooksStatus(response);
      setConnectionStatus(status);
      return status;
    } catch (err) {
      setError(err);
      showError(err.message);
      return null;
    } finally {
      setLoading(false);
    }
  }, [showError]);

  const performSync = useCallback(async (params) => {
    // Similar pattern...
  }, [showError, showSuccess]);

  return {
    loading,
    error,
    connectionStatus,
    syncResult,
    config,
    loadConnectionStatus,
    performSync,
    loadConfig,
    saveConfig
  };
}

