// quickbooksErrors.js
export const QuickBooksErrorCodes = {
  CONNECTION_FAILED: 'QB_CONNECTION_FAILED',
  AUTH_EXPIRED: 'QB_AUTH_EXPIRED',
  SYNC_FAILED: 'QB_SYNC_FAILED',
  INVALID_CONFIG: 'QB_INVALID_CONFIG',
  MISSING_ORG_ID: 'QB_MISSING_ORG_ID'
};

export class QuickBooksError extends Error {
  constructor(code, message, details = {}) {
    super(message);
    this.code = code;
    this.details = details;
    this.name = 'QuickBooksError';
  }
}

export function formatQuickBooksErrorForUI(error) {
  if (error.code === QuickBooksErrorCodes.AUTH_EXPIRED) {
    return {
      title: 'QuickBooks Session Expired',
      message: 'Please reconnect to QuickBooks to continue.',
      action: 'reconnect'
    };
  }
  // ... other error mappings
  return {
    title: 'QuickBooks Error',
    message: error.message || 'An unexpected error occurred'
  };
}

